transform_js:
transformedData = { name: 'root', children: [] };
const pathMap = { root: transformedData };
rawData.rows.forEach((row) => {
  const parts = String(row.path || '').split('/').filter(Boolean);
  if (!parts.length) {
    return;
  }
  let currentParentPath = 'root';
  let currentParentNode = transformedData;
  for (let i = 0; i < parts.length; i += 1) {
    const part = parts[i];
    const currentPath = (currentParentPath === 'root' ? '' : `${currentParentPath}/`) + part;
    const isLeaf = i === parts.length - 1;
    let node = pathMap[currentPath];
    if (!node) {
      node = { name: part, children: [] };
      pathMap[currentPath] = node;
      if (!Array.isArray(currentParentNode.children)) {
        currentParentNode.children = [];
      }
      currentParentNode.children.push(node);
    }
    if (isLeaf && typeof row.size === 'number' && row.size > 0) {
      node.value = row.size;
    }
    if (!isLeaf && !Array.isArray(node.children)) {
      node.children = [];
    }
    currentParentNode = node;
    currentParentPath = currentPath;
  }
});

